class Solution:
    def validMountainArray(self, arr):
        n = len(arr)
        if n < 3:
            return False
        inc = 1
        while inc < n and arr[inc - 1] < arr[inc]:
            inc += 1
        dec = 1
        while dec < n and arr[n - dec] < arr[n - dec - 1]:
            dec += 1
        return inc > 1 and dec > 1 and inc + dec - 1 == n

